import fReact, { useState, useEffect } from "react";
import "./App.css"; // Your CSS file where light/dark mode styles will go

const App = () => {
  const [theme, setTheme] = useState("light");

  // Load the saved theme from localStorage when the component mounts
  useEffect(() => {
    const savedTheme = localStorage.getItem("theme");
    if (savedTheme) {
      setTheme(savedTheme);
      document.body.className = savedTheme; // Apply theme to the body element
    }
  }, []);

  // Toggle the theme and save it to localStorage
  const toggleTheme = () => {
    const newTheme = theme === "light" ? "dark" : "light";
    setTheme(newTheme);
    localStorage.setItem("theme", newTheme);
    document.body.className = newTheme; // Apply theme to the body
  };

  return (
    <div className="app">
      <h1>React Light/Dark Mode</h1>
      <button onClick={toggleTheme}>
        Switch to {theme === "light" ? "Dark" : "Light"} Mode
      </button>
    </div>
  );
};

export default App;
